def solve(landStartTime: Array[Long], landDuration: Array[Long], waterStartTime: Array[Long], waterDuration: Array[Long]): Long = {
  val n = landStartTime.length
  val m = waterStartTime.length

  val landEndTimes = landStartTime.zip(landDuration).map { case (start, duration) => start + duration }
  val waterEndTimes = waterStartTime.zip(waterDuration).map { case (start, duration) => start + duration }

  var minTime = Long.MaxValue

  // Try all land attractions first, then water
  landEndTimes.foreach { landEnd =>
    val waterStart = Math.max(landEnd, waterStartTime.min)
    val waterEnd = waterStart + waterDuration.min
    minTime = Math.min(minTime, waterEnd)
  }

  // Try all water attractions first, then land
  waterEndTimes.foreach { waterEnd =>
    val landStart = Math.max(waterEnd, landStartTime.min)
    val landEnd = landStart + landDuration.min
    minTime = Math.min(minTime, landEnd)
  }

  minTime
}
